import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"Ben's Bites — 2026-04-23","description":"","frontmatter":{"title":"Ben's Bites — 2026-04-23","date":"2026-04-23T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-23-bens-bites.md","filePath":"research/ai-news/2026-04/2026-04-23-bens-bites.md","lastUpdated":1779796674000}`),n={name:"research/ai-news/2026-04/2026-04-23-bens-bites.md"};function s(i,e,l,u,h,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🍔-ben-s-bites-—-2026-04-23" tabindex="-1">🍔 Ben&#39;s Bites — 2026-04-23 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-04-23" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-04-23&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="chatgpt-s-nano-banana" tabindex="-1"><a href="https://www.bensbites.com/p/chatgpts-nano-banana" target="_blank" rel="noreferrer">ChatGPT&#39;s Nano Banana</a> <a class="header-anchor" href="#chatgpt-s-nano-banana" aria-label="Permalink to &quot;[ChatGPT&#39;s Nano Banana](https://www.bensbites.com/p/chatgpts-nano-banana)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-04-23</em></p><p>Hey folks, Keshav here.</p><p>For a few months, it felt like Google had won the image generation space. But OpenAI is back in the game. <a href="https://openai.com/index/introducing-chatgpt-images-2-0/" target="_blank" rel="noreferrer">ChatGPT Images 2.0</a> is miles ahead of anything. It’s beyond impressive at text, I haven’t seen any generation with typos, even with hundreds of words per image. See this example I created:</p><p>It’s also really good at creating realistic pictures, like this one of Professor Ben.</p><p>Oh, sorry, that one’s real. <a href="https://x.com/bentossell/status/2046824877844238520" target="_blank" rel="noreferrer">Ben was at Stanford</a> this Wednesday, teaching how to build with AI agents.</p><p>Image generation is also available in the Codex app as a skill. Use it with thinking models to get the best results—that lets it think and use code/tool calls (like creating a QR from a link, searching logos from the web) and then use them as reference images. It can also create images, reflect on them and improve the generation.</p><p>People are creating <a href="https://x.com/OpenAI/status/2046589828918317155" target="_blank" rel="noreferrer">realistic UI screenshots</a>, <a href="https://x.com/wolfejosh/status/2047028753445118445" target="_blank" rel="noreferrer">multi-page illustrated magazines</a>, <a href="https://x.com/clairevo/status/2046764362803867896" target="_blank" rel="noreferrer">personal style recommendations</a> and <a href="https://x.com/ann_nnng/status/2046888449664499805" target="_blank" rel="noreferrer">creative QR codes</a> using the new model.</p><p>The “generate UI as image” bit is interesting. Maybe there’s finally a solution to GPT-5.4’s lack of design taste. The latest coding models are fairly good at turning screenshots into code, but there are still gaps.</p><p>Last weekend, I tested a bunch of tools/models on <a href="https://x.com/Keshavatearth/status/2042529858249691590" target="_blank" rel="noreferrer">implementing a design</a> (for an ads storefront for Ben’s Bites) from a screenshot. I found:</p><p><a href="https://x.com/Keshavatearth/status/2045390815154126892" target="_blank" rel="noreferrer">Claude Design &gt; Magicpath AI</a> &gt; Raw models (like Gemini 3.1 Pro/Opus 4.6 in their web apps), when it comes to understanding the concept and making something usable, not just copying the pixel-by-pixel look (ironically, Gemini won that).</p><p>When asked to turn designs into a real working app, there was a major drift in how the apps looked. <a href="https://x.com/Keshavatearth/status/2045385400295038997" target="_blank" rel="noreferrer">Opus 4.7</a> did better than <a href="https://x.com/Keshavatearth/status/2045629048320360452" target="_blank" rel="noreferrer">GPT-5.4</a> at visually matching the reference screenshot. Though GPT-5.4’s code was more functional, and the unseen pages (like the admin panel) had a consistent design with the rest of the app.</p><p>Also, in many cases, the assets (hero image, icons, background textures) make the UI in a “generated image” stand out. When replicating that UI from a screenshot, you get the barebones UI with the correct buttons and the layout, but without those assets, and the output falls short of expectations.</p><p>Ben’s Bites is brought to you by <a href="https://www.tinyfish.ai/?utm_source=newsletter&amp;utm_medium=paid-social&amp;utm_campaign=general-developer-2026q2&amp;utm_term=bensbites" target="_blank" rel="noreferrer">TinyFish</a></p><p>Funny how AI agents can write entire apps but can’t work on the live web. Playwright scripts break, raw fetches eat your context, bot detection blocks you, nothing’s scalable. <a href="https://www.tinyfish.ai/?utm_source=newsletter&amp;utm_medium=paid-social&amp;utm_campaign=general-developer-2026q2&amp;utm_term=bensbites" target="_blank" rel="noreferrer">TinyFish</a> gives search, fetch, stealth browser, web agent, all managed in one API. <a href="https://www.tinyfish.ai/?utm_source=newsletter&amp;utm_medium=paid-social&amp;utm_campaign=general-developer-2026q2&amp;utm_term=bensbites" target="_blank" rel="noreferrer">Try it free</a>. Comes with a <a href="https://github.com/tinyfish-io/tinyfish-cookbook" target="_blank" rel="noreferrer">CLI + Skill</a>.</p><p>Headlines</p><p>OpenAI has a new product for Business, Enterprise and Edu users - <a href="https://openai.com/business/workspace-agents/" target="_blank" rel="noreferrer">Workspace Agents</a>. Codex-powered agents inside ChatGPT with a persona, task and access to external tools (like Linear) and accessible for Slack as well. These agents will also replace custom GPTs down the line (finally). <a href="https://openai.com/index/introducing-workspace-agents-in-chatgpt/" target="_blank" rel="noreferrer">Read more</a>.</p><p><a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/next-generation-gemini-deep-research/" target="_blank" rel="noreferrer">Gemini Deep Research API</a> now offers two configurations based on 3.1 Pro. It claims the best performance in web research and finding hard facts. Plus, it gets MCP support and can create charts using Nano Banana or HTML.</p><p><a href="https://x.com/SpaceX/status/2046713419978453374" target="_blank" rel="noreferrer">Cursor and SpaceX are working together</a> - Cursor will train coding models on SpaceX’s GPUs and likely share them with xAI. SpaceX can, in turn, acquire Cursor later this year for $60B, or pay $10B for the partnership if it doesn’t. On a similar note, <a href="https://x.com/TechCrunch/status/2046925764067573793" target="_blank" rel="noreferrer">Thinking Machines</a> also just signed a multi-billion-dollar Google Cloud deal.</p><p><a href="https://factory.ai/news/droid-computers" target="_blank" rel="noreferrer">Give your Droid a computer</a> - You can now give your Droid an always-on machine with its own filesystem, credentials, and config for it to keep working on your tasks. This can be in the cloud (managed by Factory), or you can bring your own device.</p><p>My feed</p><p><a href="https://chr.so/notes-to-decks" target="_blank" rel="noreferrer">Chronicle</a> - Cursor for slides. Never build a deck from scratch again. Turn ideas into stunning presentations in minutes.*</p><p><a href="https://marketplace.microsoft.com/en-us/product/office/WA200010215" target="_blank" rel="noreferrer">ChatGPT for Excel</a> and <a href="https://workspace.google.com/marketplace/app/chatgpt/870214997678" target="_blank" rel="noreferrer">Google Sheets</a> are now in beta - build new sheets, fix formulas, explain models, and update workbooks in place. (<a href="https://help.openai.com/en/articles/20001063-chatgpt-for-excel" target="_blank" rel="noreferrer">read more</a>)</p><p><a href="https://x.com/ClaudeDevs/status/2046999435239133246" target="_blank" rel="noreferrer">/ultrareview in Claude Code</a> (research preview) lets you run bug-hunting agents in the cloud before merging riskier changes like auth, data migrations, or other critical code paths.</p><p>OpenAI built an open-source viewer for chat data and Codex session logs - <a href="https://x.com/OpenAIDevs/status/2046620363568890230" target="_blank" rel="noreferrer">Euphony</a>.</p><p>Sierra is piloting an <a href="https://sierra.ai/blog/the-ai-native-interview" target="_blank" rel="noreferrer">AI-native interview</a> - debugging/review focused interviews where candidates improve a medium-sized codebase with coding agents.</p><p><a href="https://github.com/huggingface/ml-intern/tree/main" target="_blank" rel="noreferrer">ml-intern</a> from Hugging Face - open-source research agent to come up with experiments, and run them.</p><p><a href="https://x.com/garrytan/status/2046650800752279906" target="_blank" rel="noreferrer">Clawputer</a> - Managed OpenClaw agent inside an always-on sandbox.</p><p><a href="https://github.com/tw93/kami" target="_blank" rel="noreferrer">Kami</a> - design skill for AI-native docs, resumes, portfolios, long docs, and slides.</p><p><a href="https://x.com/noscroll/status/2046644280798933406" target="_blank" rel="noreferrer">noscroll</a> - an AI that doomscrolls X for you and texts you just the signal. In my experience, this is easy to claim and hard to get right.</p><p><a href="https://x.com/usemonologue/status/2046624117278085461" target="_blank" rel="noreferrer">Monologue</a> has a new Notes feature for thinking out loud when you don’t know the exact words you want to dictate.</p><p><a href="https://x.com/destraynor/status/2046995005655429344" target="_blank" rel="noreferrer">Fin</a> is moving beyond customer support into sales - using the same business context and integrations to qualify leads and book meetings.</p><p><a href="https://x.com/AravSrinivas/status/2047019688920756504" target="_blank" rel="noreferrer">Perplexity post-trained a Qwen-based model</a> to handle search and tool calls for cheaper, and it’s already serving a meaningful chunk of traffic.</p><p><a href="https://x.com/brian_lovin/status/2046737425066786990" target="_blank" rel="noreferrer">The next Slack won’t look like Slack</a>, and <a href="https://x.com/startingfromnix/status/2046643706636456427" target="_blank" rel="noreferrer">Ando</a> looks like one early attempt at that.</p><p><a href="https://x.com/leerob/status/2046788389937000576" target="_blank" rel="noreferrer">Frontend in 2026</a> - for and against the frameworks and abstractions dominant today.</p><p>Afters</p><p>@kevin2kelly called all of this in 2016 &quot;,&quot;username&quot;:&quot;jeffreyhuber&quot;,&quot;name&quot;:&quot;Jeff Huber&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1588236352797126656/i-XMejJn_normal.jpg%22,%22date%22:%222026-04-22T17:35:09.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://pbs.substack.com/media/HGhtSLoasAAZrkr.jpg%22,%22link_url%22:%22https://t.co/0YkzURdjoW%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:1,%22retweet_count%22:16,%22like_count%22:139,%22impression_count%22:58848,%22expanded_url%22:null,%22video_url%22:null,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1588236352797126656/i-XMejJn_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-22T17:35:09.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://pbs.substack.com/media/HGhtSLoasAAZrkr.jpg&quot;,&quot;link_url&quot;:&quot;https://t.co/0YkzURdjoW&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:1,&quot;retweet_count&quot;:16,&quot;like_count&quot;:139,&quot;impression_count&quot;:58848,&quot;expanded_url&quot;:null,&quot;video_url&quot;:null,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>gitperf.com &quot;,&quot;username&quot;:&quot;tnm&quot;,&quot;name&quot;:&quot;Ted Nyman&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1845213602040696832/icHPaFXs_normal.jpg%22,%22date%22:%222026-04-22T04:58:43.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://pbs.substack.com/media/HGfAQETbMAEPIX8.jpg%22,%22link_url%22:%22https://t.co/88f9cHRDt4%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:6,%22retweet_count%22:44,%22like_count%22:404,%22impression_count%22:18029,%22expanded_url%22:null,%22video_url%22:null,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1845213602040696832/icHPaFXs_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-22T04:58:43.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://pbs.substack.com/media/HGfAQETbMAEPIX8.jpg&quot;,&quot;link_url&quot;:&quot;https://t.co/88f9cHRDt4&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:6,&quot;retweet_count&quot;:44,&quot;like_count&quot;:404,&quot;impression_count&quot;:18029,&quot;expanded_url&quot;:null,&quot;video_url&quot;:null,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',48)])])}const d=t(n,[["render",s]]);export{m as __pageData,d as default};
